        self.king = kingName
        self.children = {kingName: []}
        self.dead = set()

    def birth(self, parentName, childName):
        self.children.setdefault(parentName, []).append(childName)
        self.children.setdefault(childName, [])

    def death(self, name):
        self.dead.add(name)

    def getInheritanceOrder(self):
        order = []

        def visit(person):
            if person not in self.dead:
                order.append(person)
            for kid in self.children.get(person, []):
                visit(kid)

        visit(self.king)
        return order

