class ThroneInheritance:
    def __init__(self, kingName):
        self.king = kingName
        self.kids = {}
        self.dead = set()

    def birth(self, parentName, childName):
        self.kids.setdefault(parentName, []).append(childName)

    def death(self, name):
        self.dead.add(name)

    def getInheritanceOrder(self):
        result = []
        stack = [self.king]
        while stack:
            person = stack.pop()
            if person not in self.dead:
                result.append(person)
            stack.extend(reversed(self.kids.get(person, [])))
        return result

