class ThroneInheritance {
    constructor(kingName) {
        this.king = kingName;
        this.kids = new Map();
        this.dead = new Set();
    }
    birth(parentName, childName) {
        if (!this.kids.has(parentName)) this.kids.set(parentName, []);
        this.kids.get(parentName).push(childName);
    }
    death(name) {
        this.dead.add(name);
    }
    getInheritanceOrder() {
        const result = [];
        const stack = [this.king];
        while (stack.length) {
            const person = stack.pop();
            if (!this.dead.has(person)) result.push(person);
            const children = this.kids.get(person) || [];
            for (let i = children.length - 1; i >= 0; i--) {
                stack.push(children[i]);
            }
        }
        return result;
    }
}
